import scala.collection.immutable.ArraySeq

def nums(nums: Array[Long]): Array[Long] = {
    val n = nums.length
    if (n == 0) {
        Array()
    } else if (n == 1) {
        nums
    } else {
        // Step 1: Calculate Left Max (Maximum element strictly to the left of index i)
        // Initialize with 0 since all nums[i] >= 1
        val leftMax = Array.fill(n) { 0L }
        var currentMax = 0L
        for (i <- 1 until n) {
            currentMax = math.max(currentMax, nums(i - 1))
            leftMax(i) = currentMax
        }

        // Step 2: Calculate Right Max (Maximum element strictly to the right of index i)
        // Initialize with 0
        val rightMax = Array.fill(n) { 0L }
        currentMax = 0L
        for (i <- n - 2 downto 0) {
            currentMax = math.max(currentMax, nums(i + 1))
            rightMax(i) = currentMax
        }

        // Step 3: Determine valid elements
        val result = Array.ofDim[Long](n)
        var count = 0
        for (i <- 0 until n) {
            val isValid = (nums(i) > leftMax(i)) || (nums(i) > rightMax(i))

            if (isValid) {
                result(count) = nums(i)
                count += 1
            }
        }

        // Return only the valid elements found
        result.slice(0, count)
    }
}

