def nums(arr: Array[Long]): Array[Long] = {
    val N = arr.length

    if (N <= 2) {
        return arr
    }

    // Step 1: Calculate LMax[i] = max(arr[0]...arr[i-1])
    val LMax = new Array[Long](N)
    // LMax[0] is effectively negative infinity since inputs >= 1
    LMax(0) = 0L 
    for (i <- 1 until N) {
        LMax(i) = math.max(LMax(i - 1), arr(i - 1))
    }

    // Step 2: Calculate RMax[i] = max(arr[i+1]...arr[N-1])
    val RMax = new Array[Long](N)
    // RMax[N-1] is effectively negative infinity
    RMax(N - 1) = 0L
    for (i <- (0 until N - 1).reverse) {
        RMax(i) = math.max(RMax(i + 1), arr(i + 1))
    }

    // Step 3: Collect results
    val result = scala.collection.mutable.ArrayBuffer[Long]()

    // The first element is always valid
    result.append(arr(0))

    // Check intermediate elements
    for (i <- 1 until N - 1) {
        val current = arr(i)

        // Valid if strictly greater than left max OR strictly greater than right max
        val greaterThanLeft = current > LMax(i)
        val greaterThanRight = current > RMax(i)

        if (greaterThanLeft || greaterThanRight) {
            result.append(current)
        }
    }

    // The last element is always valid
    result.append(arr(N - 1))

    result.toArray
}
